Based on the reference materials and detailed specifications, here's the complete implementation for the `add_eas_records` and `modify_eas_records_by_id` functions using the sqlgen library:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
    // Connect to the database
    auto conn = sqlgen::sqlite::connect(db_path).value();

    // Determine the table type and insert records
    if (table_name == "Student") {
        insert<Student>(conn, records.begin(), records.end()).value();
    } else if (table_name == "Course") {
        insert<Course>(conn, records.begin(), records.end()).value();
    } else if (table_name == "Score") {
        insert<Score>(conn, records.begin(), records.end()).value();
    } else if (table_name == "Major") {
        insert<Major>(conn, records.begin(), records.end()).value();
    } else {
        throw std::runtime_error("Unknown table: " + table_name);
    }
}

void modify_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id,
                              const std::string& col_name,
                              const std::optional<std::string>& new_value) {
    // Connect to the database
    auto conn = sqlgen::sqlite::connect(db_path).value();

    // Build update query based on table type
    if (table_name == "Student") {
        auto query = update<Student> | where("SNo"_c == record_id) | set(col_name"_c", new_value);
        query(conn).value();
    } else if (table_name == "Course") {
        uint32_t id = std::stoi(record_id);
        auto query = update<Course> | where("CID"_c == id) | set(col_name"_c", new_value);
        query(conn).value();
    } else if (table_name == "Score") {
        uint32_t id = std::stoi(record_id);
        auto query = update<Score> | where("ScID"_c == id) | set(col_name"_c", new_value);
        query(conn).value();
    } else if (table_name == "Major") {
        uint32_t id = std::stoi(record_id);
        auto query = update<Major> | where("MID"_c == id) | set(col_name"_c", new_value);
        query(conn).value();
    } else {
        throw std::runtime_error("Unknown table: " + table_name);
    }
}
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect(db_path)` to establish a connection to the EAS database.

2. **Insert Function**:
   - Uses `sqlgen::insert<TableType>` template with appropriate table structs (Student, Course, etc.)
   - Handles batch insertion through the vector of records
   - Uses `.value()` to extract the connection result

3. **Update Function**:
   - Uses `sqlgen::update<TableType>` template with appropriate table structs
   - Constructs queries using the pipe operator (`|`) with `where()` and `set()` clauses
   - Handles primary key conversion from string to integer where necessary
   - Uses column literals (`"SNo"_c`, `"CID"_c`) for column references
   - Supports optional values through `std::optional<std::string>`

4. **Error Handling**: Throws exceptions for unknown tables and failed operations using `.value()` extraction.

The implementation follows sqlgen's fluent API design pattern and properly handles the different data types and primary key requirements for each table in the EAS database system.

