```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return -1; // Return error code if connection fails
  }
  auto conn = conn_result.value();

  // Begin transaction
  auto begin_result = sqlgen::begin_transaction(conn);
  if (!begin_result) {
    return -1; // Return error code if transaction fails to begin
  }

  // Create delete statement with condition using sqlgen syntax
  auto delete_stmt = sqlgen::delete_from<User> | sqlgen::where("last_login"_c < "2025-01-01");

  // Execute the delete statement
  auto delete_result = delete_stmt(conn);
  if (!delete_result) {
    // Rollback transaction on failure
    auto rollback_result = conn->rollback();
    if (!rollback_result) {
      return -1; // Return error code if rollback fails
    }
    return -1; // Return error code if delete fails
  }

  // Commit the transaction
  auto commit_result = conn->commit();
  return commit_result.value() ? 0 : -1; // Return 0 on success, -1 on failure
}

} // namespace delete_inactive_users
