    // 2. Create tables using sqlgen's create_table function
    sqlgen::create_table<Customer>(conn);
    sqlgen::create_table<Order>(conn);
    sqlgen::create_table<OrderItem>(conn);
    sqlgen::create_table<Product>(conn);

    // 3. Build the query using sqlgen's fluent interface
    auto query = sqlgen::select_from<Customer>(
