#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");
    bool success = false;
    try {
        conn->begin_transaction();

        // Deduct from sender with condition
        auto result1 = conn->execute(
            sqlgen::update<Account>(from_account_id)
                .set(sqlgen::col<"balance">() = sqlgen::col<"balance">() - amount)
                .where(sqlgen::col<"balance">() >= amount)
        );

        if (!result1 || result1.affected_rows() != 1) {
            throw std::runtime_error("Insufficient funds or sender update failed");
        }

        // Add to receiver
        auto result2 = conn->execute(
            sqlgen::update<Account>(to_account_id)
                .set(sqlgen::col<"balance">() = sqlgen::col<"balance">() + amount)
        );

        if (!result2 || result2.affected_rows() != 1) {
            throw std::runtime_error("Receiver update failed");
        }

        success = true;
    } catch (...) {
        conn->rollback();
        success = false;
    }

    if (!success) {
        conn->rollback();
    }
    return success;
}

}  // namespace transaction_transfer_funds

