  EXPECT_TRUE(success);

  // 3. Select from the view and verify aggregated results
  auto query = sqlgen::read<std::vector<SalesSummary>> | order_by("product_name"_c);
  auto result = query(conn).value();

  // Widget A: total quantity 5, total revenue 50.0
  // Widget B: total quantity 1, total revenue 20.0

